var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MEMBER_NPC_ESPR2_OLD","text":{"KOREA":"발렌티누스가 하이드리히 소장을 견제하는 건… 역시 그 날의 원한 때문인가?","JPN":"バレンチヌスがハイドリヒ所長を牽制するのは……やはりあの日の恨みか？","ENG":"Is Valentinus keeping Chief Heydrich in check because of the grudge they've held since that day?","TWN":"聖華倫牽制海德里希所長……果然還是因為那天的仇怨嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MEMBER_NPC_ESPR2_YOUNG","text":{"KOREA":"하지만 대세는 생물학부로 기울었습니다.","JPN":"ですが、世論は生物学部寄りです。","ENG":"Nevertheless, the tides have shifted to the Biology Department.","TWN":"不過感覺局勢偏向生物學院了。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_NPC_ESPR2_YOUNG","text":{"KOREA":"당장 호수에 대한 연구를 중단하라는데 좋아할 학부가 있을 리 없죠.","JPN":"今すぐ湖の研究を中断しろと言われて喜ぶ学部があるわけないです。","ENG":"Also, none of the deans will like to hear that they will have to stop their research effectively immediately.","TWN":"如果讓他們馬上停止對湖水的研究，不會有任何學院同意。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_NPC_ESPR2_OLD","text":{"KOREA":"이번 학회장도 통찰력이 남다르시니 말이야. 맥크레디 집안이 아니더라도……","JPN":"今度の学会長の洞察力は並みではないからな。マクレディー家でなくても……","ENG":"The current President has good insight, so even if she is not a MacCready...","TWN":"這次學會長也很有洞察力呢。要不是麥克蕾蒂家族……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"발언에 주의해 주시죠. 맥크레디 가문은 쉽게 입에 올릴 이름이 아닙니다.","JPN":"発言にご注意ください。マクレディー家の名は気軽に口にするものではありません。","ENG":"Please refrain from making such remarks. The MacCready name is not one to be spoken so easily.","TWN":"請注意你們的言論。麥克蕾蒂家族不是你們可以妄議的。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_QM","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER_NPC_ESPR2_OLD","text":{"KOREA":"라, 람다 법학부장? 언제 오셨소?","JPN":"ら、ラムダ法学部長？　いつおいでに？","ENG":"D-Dean Lamda? When did you get here?","TWN":"蘭…蘭達法學院院長，你什麼時候來的？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_QM","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"열차가 연착되어 방금 도착했습니다. 예상 시각보다 3분 12초 초과했네요.","JPN":"列車が遅れて今到着したところです。予想時刻より3分12秒過ぎてしまいました。","ENG":"Just now. My train was delayed. It took me an additional 3 minutes and 12 seconds to arrive here.","TWN":"列車誤點了，所以我剛剛才到。比預計時間晚了3分12秒。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"토론 중에 죄송합니다. 법학부장 람다 스파타리, 발언하겠습니다.","JPN":"議論中に申し訳ございません。法学部長ラムダ・スパタリー、発言いたします。","ENG":"I'm sorry for the interruption. But I, Lamda Spatari, Dean of Law, would like to speak.","TWN":"很抱歉打斷大家的討論。我是法學院院長蘭達·史派特，我要發言。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠, 뜻대로 하시오.","JPN":"ふん、好きにしたまえ。","ENG":"Hmm... Very well. As you please.","TWN":"嗯，你請說。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"참견쟁이께서 오셨네. 말싸움이 너무 과했나.","JPN":"お節介焼きが来たわね。口げんかが過ぎたかしら。","ENG":"Looks like our mediator is here. Perhaps we got a little carried away?","TWN":"愛管閒事的人來了呢。剛才我們太沉浸於鬥嘴了嗎。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회의 크고 작은 행사는 본래 법학부의 참관 하에 이루어지게 되어 있습니다.","JPN":"学会の行事という行事は元々法学部参席の上で行われるようになっています。","ENG":"All events of the Society, small or large, must be held under the supervision of the law department.","TWN":"學會大大小小的活動，本來就是在法學院的見證下完成的。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회장 대행이 불참한 자리에서 학회의 운영 방침을 논의하는 것은 월권 행위에 속합니다.","JPN":"学会長代行が不参加の場で学会の運営方針を議論することは越権行為に当たります。","ENG":"Furthermore, discussing the Society policies in the absence of the Acting President constitutes an abuse of authority.","TWN":"在代理學會長缺席的情況下，探討學會的運營方針屬於越權行為。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"본래라면 주최자에 대한 처벌이 이루어져야겠지만……","JPN":"本来なら主催者への処罰が実施されるはずですが……","ENG":"The organizer of this event should be punished. However...","TWN":"本來應該對主辦者進行處罰……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"오늘만큼은 맥크레디 가문의 후광을 고맙게 여기셔야겠군요, 부학회장님.","JPN":"今日だけはマクレディー家の名に感謝すべきですね、副学会長。","ENG":"You should be thankful that you are a MacCready today, Vice President.","TWN":"但至少今天你要感謝麥克蕾蒂家族的光環，副學會長。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 학회장이 아닌 자들은 학회의 방향성에 대해 거론조차 할 수 없다는 건가요?","JPN":"では、学会長でない者は学会の方向性について言及すらできないというのですか？","ENG":"Are you saying that only the President can decide matters of the Society?","TWN":"那你的意思是學會長之外的人，連學會未來的方向都不能討論嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"규정에 따르면 그렇습니다.","JPN":"規定によりますとそうなります。","ENG":"According to the rules, yes.","TWN":"按照規定來說，是的。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님께서도 그걸 알고 학회장 대행이 부재 중일 때 회동을 가지신 것 아닌가요?","JPN":"副学会長もそれをご存じの上で学会長代行が不在である時に会合を開いたのではないですか？","ENG":"Did you not plan this meeting fully knowing that the Acting President would be unable to attend?","TWN":"副學會長不也是知道這一點，才會選擇代理學會長不在的時候，召開會議嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};